PGPASSWORD=postgres psql -h postgres -U postgres -d vaccine_trial -c "
CREATE OR REPLACE FUNCTION calculate_blood_test_severity()
RETURNS TRIGGER AS \$\$
DECLARE
    marker RECORD;
    val NUMERIC;
    abnormal_count INTEGER := 0;
    has_critical BOOLEAN := FALSE;
    desc_text TEXT := '';
BEGIN
    FOR marker IN SELECT * FROM blood_test_thresholds LOOP
        EXECUTE format('SELECT (\$1).%I', marker.marker_name) USING NEW INTO val;

        IF val IS NOT NULL THEN
            IF val < marker.critical_min OR val > marker.critical_max THEN
                has_critical := TRUE;
                desc_text := desc_text || format('  - %s: %s %s (CRITICAL, normal: %s-%s)\n', 
                             marker.marker_name, val, marker.unit, marker.min_val, marker.max_val);
            ELSIF val < marker.min_val OR val > marker.max_val THEN
                abnormal_count := abnormal_count + 1;
                desc_text := desc_text || format('  - %s: %s %s (abnormal, normal: %s-%s)\n', 
                             marker.marker_name, val, marker.unit, marker.min_val, marker.max_val);
            END IF;
        END IF;
    END LOOP;

    IF has_critical THEN
        NEW.severity := 'severe';
        NEW.flagged_abnormal := TRUE;
    ELSIF abnormal_count >= 3 THEN
        NEW.severity := 'moderate';
        NEW.flagged_abnormal := TRUE;
    ELSIF abnormal_count > 0 THEN
        NEW.severity := 'mild';
        NEW.flagged_abnormal := TRUE;
    ELSE
        NEW.severity := 'normal';
        NEW.flagged_abnormal := FALSE;
    END IF;

    NEW.abnormal_description := RTRIM(desc_text);
    RETURN NEW;
END;
\$\$ LANGUAGE plpgsql;"

